module otsu_threshold(
    input [7:0] pixel_value,
    input [7:0] threshold,
    output reg binary_output
);
  wire [7:0] _tap_pixel_value = pixel_value & {8{1'b1}};

    always @(*) begin
        if (pixel_value > threshold) begin
            binary_output = 1;
        end else begin
            binary_output = 0;
        end
    end
endmodule
